private Path resolveConfigPath(String name) throws IOException {
        if (!name.matches("[A-Za-z0-9_-]+")) {
            throw new IOException("Invalid configuration name");
        }
        Path dir = ROOT.resolve(name);
        return dir.resolve("settings.conf");
    }
